diff --git a/web/src/pages/account/index.tsx b/web/src/pages/account/index.tsx
index c0c3f2e1..861bf89e 100644
--- a/web/src/pages/account/index.tsx
+++ b/web/src/pages/account/index.tsx
@@ -199,6 +199,426 @@ function PageInner({
     getUserInfo();
   }, []);

+  const renderAccountTab = () => (
+    <Paper
+      sx={{
+        p: 3,
+        position: 'relative',
+        overflowWrap: 'break-word',
+      }}
+    >
+      <IconButton
+        color="primary"
+        href={PAGE_INFO.ACCOUNT_EDIT.href(AccountTab)}
+        sx={{ position: 'absolute', top: 20, right: 20 }}
+      >
+        <Edit />
+      </IconButton>
+      <Stack direction="column">
+        <Typography sx={{ mb: 3 }} variant="h2">
+          {translate('account')}
+        </Typography>
+        <Grid container spacing={3}>
+          <Grid size={{ sm: 6, xs: 12 }}>
+            <FormControl fullWidth sx={{ mb: 2 }}>
+              <FormLabel>
+                <Typography variant="h4">
+                  {translate('email')}
+                </Typography>
+              </FormLabel>
+              <Typography>{currentUser.email}</Typography>
+            </FormControl>
+          </Grid>
+          <Grid size={{ sm: 6, xs: 12 }}>
+            <FormControl fullWidth sx={{ mb: 2 }}>
+              <FormLabel>
+                <Typography variant="h4">
+                  {translate('language')}
+                </Typography>
+              </FormLabel>
+              <Typography>
+                {
+                  _.find(
+                    SUPPORTED_LANGUAGES,
+                    (x) => x.value == currentLang,
+                  )?.name
+                }
+              </Typography>
+            </FormControl>
+            <FormControl fullWidth sx={{ mb: 2 }}>
+              <FormLabel>
+                <Typography variant="h4">
+                  {translate('unit')}
+                </Typography>
+              </FormLabel>
+              <Typography>
+                {
+                  _.find(
+                    SUPPORTED_UNITS,
+                    (x) => x.value == currentUnit,
+                  )?.name
+                }
+              </Typography>
+            </FormControl>
+          </Grid>
+        </Grid>
+        <Divider sx={{ my: 3 }} />
+        <Stack direction="column" spacing={2}>
+          <Typography sx={{ mb: 3 }} variant="h2">
+            {translate('support')}
+          </Typography>
+          <Stack
+            direction={isSmallScreen ? 'column' : 'row'}
+            spacing={2}
+          >
+            <Button
+              variant="outlined"
+              color="primary"
+              href={
+                currentLang === 'ja'
+                  ? '/terms-of-use?lang=ja'
+                  : '/terms-of-use?lang=en'
+              }
+              fullWidth={isSmallScreen}
+              sx={{ flex: 1 }}
+            >
+              {translate('open_terms_of_use')}
+            </Button>
+            <Button
+              variant="outlined"
+              color="primary"
+              href={
+                currentLang === 'ja'
+                  ? '/privacy-policy?lang=ja'
+                  : '/privacy-policy?lang=en'
+              }
+              fullWidth={isSmallScreen}
+              sx={{ flex: 1 }}
+            >
+              {translate('open_privacy_policy')}
+            </Button>
+            {showContactFormButton && contactFormUrl && (
+              <Button
+                variant="outlined"
+                color="primary"
+                href={contactFormUrl}
+                target="_blank"
+                rel="noopener noreferrer"
+                fullWidth={isSmallScreen}
+                sx={{ flex: 1 }}
+              >
+                {translate('open_contact_form')}
+              </Button>
+            )}
+          </Stack>
+        </Stack>
+      </Stack>
+    </Paper>
+  );
+
+  const renderTeamTab = () => (
+    <Paper
+      sx={{
+        p: 3,
+        position: 'relative',
+        overflowWrap: 'break-word',
+      }}
+    >
+      {teams.length >= 2 && (
+        <IconButton
+          color="primary"
+          href={PAGE_INFO.ACCOUNT_EDIT.href(TeamTab)}
+          sx={{ position: 'absolute', top: 20, right: 20 }}
+        >
+          <Edit />
+        </IconButton>
+      )}
+      <Stack direction="column">
+        <Typography sx={{ mb: 3 }} variant="h2">
+          {translate('team_info')}
+        </Typography>
+        <Grid container spacing={3}>
+          <Grid size={{ sm: 6, xs: 12 }}>
+            <FormControl fullWidth sx={{ mb: 2 }}>
+              <FormLabel>
+                <Typography variant="h4">
+                  {translate('team_displayed')}
+                </Typography>
+              </FormLabel>
+              <Typography>{currentTeam.name}</Typography>
+            </FormControl>
+            <FormControl fullWidth sx={{ mb: 2 }}>
+              <FormLabel>
+                <Typography variant="h4">
+                  {translate('team_type')}
+                </Typography>
+              </FormLabel>
+              <Typography>
+                {translate(
+                  currentTeam.teamType === TeamType.SINGLE
+                    ? 'team_type_single'
+                    : 'team_type_multiple',
+                )}
+              </Typography>
+            </FormControl>
+            <FormControl fullWidth sx={{ mb: 2 }}>
+              <FormLabel>
+                <Typography variant="h4">
+                  {translate('role')}
+                </Typography>
+              </FormLabel>
+              {_.map(
+                currentUser.getUserRoles(currentTeam.id),
+                (userRole) => {
+                  return (
+                    <Box key={userRole.id} sx={{ mb: 1 }}>
+                      <AppRoleChip roleGroup={userRole.roleGroup} />
+                      <Typography component="div">
+                        {userRoleToDescription(
+                          userRole.roleGroup.name,
+                        )}
+                      </Typography>
+                    </Box>
+                  );
+                },
+              )}
+            </FormControl>
+          </Grid>
+          <Grid size={{ sm: 6, xs: 12 }}>
+            {(currentTeam.teamPlan || currentTeam.nextTeamPlan) && (
+              <>
+                {currentTeam.teamPlan && (
+                  <>
+                    <FormControl fullWidth sx={{ mb: 2 }}>
+                      <FormLabel>
+                        <Typography variant="h4">
+                          {translate('plan_name')}
+                        </Typography>
+                      </FormLabel>
+                      <Typography>
+                        {currentTeam.teamPlan.plan.name}
+                      </Typography>
+                      {currentTeam.teamPlan.isInAppleSubscription && (
+                        <Typography
+                          variant="caption"
+                          color="text.secondary"
+                          sx={{ mt: 1, display: 'block' }}
+                        >
+                          {translate(
+                            'apple_subscription_active_notice',
+                          )}
+                        </Typography>
+                      )}
+                    </FormControl>
+
+                    {currentTeam.teamPlan.plan.isPaid && (
+                      <>
+                        <FormControl fullWidth sx={{ mb: 2 }}>
+                          <FormLabel>
+                            <Typography variant="h4">
+                              {translate('validity_period')}
+                            </Typography>
+                          </FormLabel>
+                          <Typography>
+                            {moment(
+                              currentTeam.teamPlan.startDate,
+                            ).format(DATETIME_FORMAT)}
+                            {' - '}
+                            {moment(
+                              currentTeam.teamPlan.endDate,
+                            ).format(DATETIME_FORMAT)}
+                          </Typography>
+                          {currentTeam.teamType === TeamType.SINGLE &&
+                            !currentTeam.teamPlanCancelAt &&
+                            currentTeam.teamPlan
+                              .isInStripeSubscription && (
+                              <Typography
+                                variant="caption"
+                                color="text.secondary"
+                                sx={{ mt: 1, display: 'block' }}
+                              >
+                                {translate(
+                                  'subscription_cancellation_notice',
+                                )}
+                              </Typography>
+                            )}
+                        </FormControl>
+                      </>
+                    )}
+
+                    {currentTeam.teamPlanCancelAt && (
+                      <FormControl fullWidth sx={{ mb: 2 }}>
+                        <FormLabel>
+                          <Typography variant="h4" color="warning.main">
+                            {translate('plan_cancellation_scheduled')}
+                          </Typography>
+                        </FormLabel>
+                        <Typography color="warning.main">
+                          {moment(currentTeam.teamPlanCancelAt).format(
+                            DATETIME_FORMAT,
+                          )}
+                        </Typography>
+                      </FormControl>
+                    )}
+
+                    {currentTeam.teamPlanDowngradeAt && (
+                      <FormControl fullWidth sx={{ mb: 2 }}>
+                        <FormLabel>
+                          <Typography variant="h4" color="warning.main">
+                            {translate('plan_downgrade_scheduled')}
+                          </Typography>
+                        </FormLabel>
+                        <Typography color="warning.main">
+                          {moment(
+                            currentTeam.teamPlanDowngradeAt,
+                          ).format(DATETIME_FORMAT)}
+                          {(() => {
+                            const plan = getPlanById(
+                              currentTeam.downgradePlanId ?? '',
+                            );
+                            return plan
+                              ? ` — ${translate(plan.nameKey)}`
+                              : '';
+                          })()}
+                        </Typography>
+                      </FormControl>
+                    )}
+                  </>
+                )}
+
+                {currentTeam.nextTeamPlan && (
+                  <>
+                    <FormControl fullWidth sx={{ mb: 2 }}>
+                      <FormLabel>
+                        <Typography variant="h4">
+                          {translate('next_plan_name')}
+                        </Typography>
+                      </FormLabel>
+                      <Typography>
+                        {currentTeam.nextTeamPlan.plan.name}
+                      </Typography>
+                    </FormControl>
+                    <FormControl fullWidth sx={{ mb: 2 }}>
+                      <FormLabel>
+                        <Typography variant="h4">
+                          {translate('next_validity_period')}
+                        </Typography>
+                      </FormLabel>
+                      <Typography>
+                        {moment(
+                          currentTeam.nextTeamPlan.startDate,
+                        ).format(DATETIME_FORMAT)}
+                        {' - '}
+                        {moment(
+                          currentTeam.nextTeamPlan.endDate,
+                        ).format(DATETIME_FORMAT)}
+                      </Typography>
+                    </FormControl>
+                  </>
+                )}
+
+                {(currentTeam.teamType !== TeamType.MULTIPLE) &&
+                  currentTeam.teamPlan?.stripeSubscription && (
+                    <FormControl fullWidth>
+                      <Button
+                        variant="outlined"
+                        color="primary"
+                        onClick={handleBillingPortal}
+                        disabled={isSubmitting}
+                      >
+                        {translate('open_billing_portal')}
+                      </Button>
+                    </FormControl>
+                )}
+              </>
+            )}
+
+            {/* 総使用量 */}
+            <FormControl fullWidth sx={{ mt: 4, mb: 2 }}>
+              <FormLabel>
+                <Typography variant="h4">
+                  {translate('total_usage')}
+                </Typography>
+              </FormLabel>
+              { currentTeam.currentTotalBallAvailableCount || currentTeam.currentTotalAiCoachAvailableCount ? (
+                <>
+                  { currentTeam.currentTotalBallAvailableCount ?
+                    <Typography>
+                      <Typography component="span" variant="inherit">
+                        {translate('analyzed_balls')}
+                        {' : '}
+                      </Typography>
+                      <Typography component="span" variant="inherit">
+                        {StringUtil.getTeamItemBallUsageString(
+                          currentTeam,
+                        )}
+                      </Typography>
+                    </Typography>
+                    : <></>
+                  }
+                  { currentTeam.currentTotalAiCoachAvailableCount ?
+                    <Typography>
+                      <Typography component="span" variant="inherit">
+                        {translate('ai_coach_usage')}
+                        {' : '}
+                      </Typography>
+                      <Typography component="span" variant="inherit">
+                        {StringUtil.getTeamItemAiCoachUsageString(
+                          currentTeam,
+                        )}
+                      </Typography>
+                    </Typography>
+                    : <></>
+                  }
+                </>
+              ) : (
+                <Typography component="span" variant="inherit">
+                  -
+                </Typography>
+              )}
+            </FormControl>
+          </Grid>
+        </Grid>
+      </Stack>
+    </Paper>
+  );
+
+  const renderChangePasswordTab = () => (
+    <Paper
+      sx={{
+        p: 3,
+        position: 'relative',
+      }}
+    >
+      <IconButton
+        color="primary"
+        href={PAGE_INFO.ACCOUNT_EDIT.href(ChangePasswordTab)}
+        sx={{ position: 'absolute', top: 20, right: 20 }}
+      >
+        <Edit />
+      </IconButton>
+      <Stack direction="column" spacing={3}>
+        <Typography variant="h2">
+          {translate('change_password')}
+        </Typography>
+        <FormControl>
+          <Stack direction="row" spacing={1}>
+            <Typography>
+              {translate('password_last_change')}
+            </Typography>
+            <Typography fontWeight="bold">
+              {currentUser?.passwordUpdatedDate
+                ? moment(currentUser?.passwordUpdatedDate).format(
+                  'YYYY-MM-DD',
+                )
+                : '-'}
+            </Typography>
